code = """import json

# Get data from query results
non_python_data = globals()['var_functions.query_db:76']
readme_data = globals()['var_functions.query_db:66']

print('Data types:', type(non_python_data), type(readme_data))

# Process the data
if isinstance(non_python_data, list) and isinstance(readme_data, list):
    # Extract repo names
    non_python_names = {item['repo_name'] for item in non_python_data if isinstance(item, dict) and 'repo_name' in item}
    
    # Filter READMEs
    filtered_readmes = [readme for readme in readme_data 
                       if isinstance(readme, dict) and 
                       readme.get('sample_repo_name') in non_python_names]
    
    # Count copyright
    copyright_terms = ['copyright', 'Copyright', '©', '(c)', '(C)']
    copyright_count = sum(1 for readme in filtered_readmes 
                         if any(term in (readme.get('content', '') or '') for term in copyright_terms))
    
    # Calculate proportion
    total = len(filtered_readmes)
    proportion = copyright_count / total if total > 0 else 0
    
    result = {
        'non_python_repos': len(non_python_names),
        'readme_files': total,
        'copyright_found': copyright_count,
        'proportion': round(proportion, 4),
        'percentage': round(proportion * 100, 2)
    }
else:
    result = {'error': 'Invalid data format'}

print('__RESULT__:')
print(json.dumps(result))"""

